static constexpr uint32_t ALIGN_ELEMS = 128;
static constexpr uint32_t MAX_TILE_AREA = 8192;

static inline uint32_t AlignDown(uint32_t x, uint32_t a) {
    return (x / a) * a;
}

static inline uint32_t CeilDiv(uint32_t a, uint32_t b) {
    return (a + b - 1u) / b;
